#!/usr/bin/env bash
# Freddy Fix It — payments UX pass:
#   • Confirm popups on Pay / Confirm&release / Mark complete / Withdraw / Choose bid
#   • Slide-in chat drawer (behind a button) for client + contractor, read-only after completion
