__EOF_src_pages_ContractorDashboard_tsx__

mkdir -p "$(dirname src/pages/ClientDashboard.tsx)"
base64 -d > "src/pages/ClientDashboard.tsx" <<'__EOF_src_pages_ClientDashboard_tsx__'

__EOF_src_pages_ClientDashboard_tsx__

mkdir -p "$(dirname supabase/functions/notify-email/index.ts)"
base64 -d > "supabase/functions/notify-email/index.ts" <<'__EOF_supabase_functions_notify-email_index_ts__'

__EOF_supabase_functions_notify-email_index_ts__

